using Microsoft.EntityFrameworkCore;
using TextilSalas.Domain.Entities;

namespace TextilSalas.Infrastructure.Data;

public sealed class AppDbContext(DbContextOptions<AppDbContext> options) : DbContext(options)
{
    public DbSet<Category> Categories => Set<Category>();
    public DbSet<Product> Products => Set<Product>();
    public DbSet<ProductImage> ProductImages => Set<ProductImage>();
    public DbSet<Order> Orders => Set<Order>();
    public DbSet<Profile> Profiles => Set<Profile>();
    public DbSet<Quotation> Quotations => Set<Quotation>();
    public DbSet<Setting> Settings => Set<Setting>();

    protected override void OnModelCreating(ModelBuilder b)
    {
        b.HasDefaultSchema("public");
        b.Entity<Category>(e => { e.ToTable("categories"); e.Property(x=>x.Id).HasColumnName("id"); e.Property(x=>x.Name).HasColumnName("name"); e.Property(x=>x.Description).HasColumnName("description"); e.Property(x=>x.Icon).HasColumnName("icon"); e.Property(x=>x.IsActive).HasColumnName("is_active"); e.Property(x=>x.SortOrder).HasColumnName("sort_order"); e.Property(x=>x.CreatedAt).HasColumnName("created_at"); e.Property(x=>x.UpdatedAt).HasColumnName("updated_at"); });
        b.Entity<Product>(e => { e.ToTable("products"); e.Property(x=>x.Id).HasColumnName("id"); e.Property(x=>x.Name).HasColumnName("name"); e.Property(x=>x.CategoryId).HasColumnName("category_id"); e.Property(x=>x.Price).HasColumnName("price"); e.Property(x=>x.Stock).HasColumnName("stock"); e.Property(x=>x.Material).HasColumnName("material"); e.Property(x=>x.Description).HasColumnName("description"); e.Property(x=>x.ShortDescription).HasColumnName("short_description"); e.Property(x=>x.Gramaje).HasColumnName("gramaje"); e.Property(x=>x.Sizes).HasColumnName("sizes"); e.Property(x=>x.IsActive).HasColumnName("is_active"); e.Property(x=>x.IsFeatured).HasColumnName("is_featured"); e.Property(x=>x.CreatedAt).HasColumnName("created_at"); e.Property(x=>x.UpdatedAt).HasColumnName("updated_at"); e.HasMany(x=>x.Images).WithOne(x=>x.Product).HasForeignKey(x=>x.ProductId); });
        b.Entity<ProductImage>(e => { e.ToTable("product_images"); e.Property(x=>x.Id).HasColumnName("id"); e.Property(x=>x.ProductId).HasColumnName("product_id"); e.Property(x=>x.ImageUrl).HasColumnName("image_url"); e.Property(x=>x.SortOrder).HasColumnName("sort_order"); e.Property(x=>x.CreatedAt).HasColumnName("created_at"); });
        b.Entity<Order>(e => { e.ToTable("orders"); e.Property(x=>x.Id).HasColumnName("id"); e.Property(x=>x.UserId).HasColumnName("user_id"); e.Property(x=>x.OrderNumber).HasColumnName("order_number"); e.Property(x=>x.Email).HasColumnName("email"); e.Property(x=>x.Status).HasColumnName("status"); e.Property(x=>x.PaymentStatus).HasColumnName("payment_status"); e.Property(x=>x.DeliveryType).HasColumnName("delivery_type"); e.Property(x=>x.Department).HasColumnName("department"); e.Property(x=>x.Province).HasColumnName("province"); e.Property(x=>x.District).HasColumnName("district"); e.Property(x=>x.FullAddress).HasColumnName("full_address"); e.Property(x=>x.PaymentMethod).HasColumnName("payment_method"); e.Property(x=>x.PaymentReference).HasColumnName("payment_reference"); e.Property(x=>x.Items).HasColumnName("items").HasColumnType("jsonb"); e.Property(x=>x.Subtotal).HasColumnName("subtotal"); e.Property(x=>x.Discount).HasColumnName("discount"); e.Property(x=>x.ShippingCost).HasColumnName("shipping_cost"); e.Property(x=>x.Igv).HasColumnName("igv"); e.Property(x=>x.Total).HasColumnName("total"); e.Property(x=>x.WantsInvoice).HasColumnName("wants_invoice"); e.Property(x=>x.Ruc).HasColumnName("ruc"); e.Property(x=>x.RazonSocial).HasColumnName("razon_social"); e.Property(x=>x.BoletaNumber).HasColumnName("boleta_number"); e.Property(x=>x.PaymentProofUrl).HasColumnName("payment_proof_url"); e.Property(x=>x.PaymentOperationNumber).HasColumnName("payment_operation_number"); e.Property(x=>x.PaymentSubmittedAt).HasColumnName("payment_submitted_at"); e.Property(x=>x.PaymentRejectionReason).HasColumnName("payment_rejection_reason"); e.Property(x=>x.PaymentValidatedAt).HasColumnName("payment_validated_at"); e.Property(x=>x.PaymentValidatedBy).HasColumnName("payment_validated_by"); e.Property(x=>x.CreatedAt).HasColumnName("created_at"); });
        b.Entity<Quotation>(e => { e.ToTable("quotations"); e.Property(x=>x.Id).HasColumnName("id"); e.Property(x=>x.ContactName).HasColumnName("contact_name"); e.Property(x=>x.LastName).HasColumnName("last_name"); e.Property(x=>x.Company).HasColumnName("company"); e.Property(x=>x.Ruc).HasColumnName("ruc"); e.Property(x=>x.Email).HasColumnName("email"); e.Property(x=>x.Phone).HasColumnName("phone"); e.Property(x=>x.BusinessType).HasColumnName("business_type"); e.Property(x=>x.ProductInterest).HasColumnName("product_interest"); e.Property(x=>x.Quantity).HasColumnName("quantity"); e.Property(x=>x.Details).HasColumnName("details"); e.Property(x=>x.Status).HasColumnName("status"); e.Property(x=>x.Priority).HasColumnName("priority"); e.Property(x=>x.EstimatedAmount).HasColumnName("estimated_amount"); e.Property(x=>x.Location).HasColumnName("location"); e.Property(x=>x.LastContactDate).HasColumnName("last_contact_date"); e.Property(x=>x.FollowUpDate).HasColumnName("follow_up_date"); e.Property(x=>x.InternalNotes).HasColumnName("internal_notes"); e.Property(x=>x.CreatedAt).HasColumnName("created_at"); });
        b.Entity<Profile>(e => { e.ToTable("profiles"); e.Property(x=>x.Id).HasColumnName("id"); e.Property(x=>x.UserId).HasColumnName("user_id"); e.Property(x=>x.FirstName).HasColumnName("first_name"); e.Property(x=>x.LastName).HasColumnName("last_name"); e.Property(x=>x.MaternalLastName).HasColumnName("maternal_last_name"); e.Property(x=>x.Dni).HasColumnName("dni"); e.Property(x=>x.Gender).HasColumnName("gender"); e.Property(x=>x.Phone).HasColumnName("phone"); e.Property(x=>x.CreatedAt).HasColumnName("created_at"); e.Property(x=>x.UpdatedAt).HasColumnName("updated_at"); });
        b.Entity<Setting>(e => { e.ToTable("settings"); e.HasKey(x=>x.Key); e.Property(x=>x.Key).HasColumnName("key"); e.Property(x=>x.Value).HasColumnName("value").HasColumnType("jsonb"); e.Property(x=>x.UpdatedAt).HasColumnName("updated_at"); });
    }
}
